/* Stage 1 GAEB — structural extraction + AI context preparation
 * Derives only fields that are unambiguous from the GAEB XML structure.
 * Human-readable metadata (title, buyer, region, deadline, trade_category)
 * is handled by the extract-metadata-llm node that follows.
 */
const input = $json;
const gaebFiles = input.gaeb_files || [];

function deriveTrade(g) {
  const entries = g?.bill_of_quantities?.entries || [];
  for (const e of entries) {
    if (e.type === 'item' && e.category_path?.length > 0) return e.category_path[0];
  }
  return null;
}

// Serialise GAEB BoQ text for stage 2 requirements extraction
function serializeGaebText(gaebFiles) {
  const lines = [];
  for (const g of gaebFiles) {
    if (g._error) continue;
    const label = g.bill_of_quantities?.label || g.project?.label || g.project?.name || g.file;
    const owner = g.owner?.name || null;
    lines.push('# ' + label);
    if (owner) lines.push('Auftraggeber: ' + owner);
    if (g.award_no) lines.push('Vergabe-Nr.: ' + g.award_no);
    lines.push('');
    for (const block of (g.award_description || [])) {
      if (block.outline) lines.push('## ' + block.outline);
      if (block.detail) lines.push(block.detail);
      lines.push('');
    }
    const entries = g.bill_of_quantities?.entries || [];
    const seenCats = new Set();
    let shown = 0;
    for (const e of entries) {
      if (e.type === 'item' && shown < 40) {
        const catKey = (e.category_path || []).slice(0, -1).join(' > ');
        if (catKey && !seenCats.has(catKey)) { seenCats.add(catKey); lines.push('\n### ' + catKey); }
        lines.push('- [' + e.position + '] ' + (e.short_text || '') + (e.unit ? ' (' + e.quantity + ' ' + e.unit + ')' : ''));
        if (e.long_text) lines.push('  ' + e.long_text.split('\n')[0].slice(0, 120));
        shown++;
      }
    }
    lines.push('\n(' + (g.bill_of_quantities?.total_items || 0) + ' Positionen gesamt)');
  }
  return lines.join('\n');
}

// Build rich context string for AI metadata extraction
function buildContextForAI(gaebFiles, archiveSummary, pdfTexts) {
  const lines = [];
  const gaebLikeExts = ['.d81','.d82','.d83','.d84','.d85','.d86','.x81','.x82','.x83','.x84','.x85','.x86'];

  for (const g of gaebFiles) {
    if (g._error) {
      lines.push('PARSE_ERROR: ' + String(g._error).slice(0, 600));
    } else {
      if (g.project?.name)                lines.push('Projekt-Name (XML): ' + g.project.name);
      if (g.project?.label)               lines.push('Projekt-Label (XML): ' + g.project.label);
      if (g.bill_of_quantities?.label)    lines.push('LV-Bezeichnung: ' + g.bill_of_quantities.label);
      if (g.bill_of_quantities?.name)     lines.push('LV-Name: ' + g.bill_of_quantities.name);
      if (g.award_no)                     lines.push('Vergabe-Nr.: ' + g.award_no);
      if (g.owner?.name)                  lines.push('Auftraggeber: ' + g.owner.name);
      if (g.owner?.city)                  lines.push('Ort: ' + g.owner.city);
      if (g.metadata?.deadline)           lines.push('Abgabefrist (XML): ' + g.metadata.deadline);
      if (g.metadata?.data_phase)         lines.push('GAEB-Phase: ' + g.metadata.data_phase);
      for (const block of (g.award_description || []).slice(0, 5)) {
        if (block.outline) lines.push('Beschreibung: ' + block.outline);
        if (block.detail)  lines.push(block.detail.slice(0, 300));
      }
      const catPaths = new Set();
      for (const e of (g.bill_of_quantities?.entries || [])) {
        if (e.type === 'item' && e.category_path?.length > 0) { catPaths.add(e.category_path[0]); if (catPaths.size >= 5) break; }
      }
      if (catPaths.size > 0) lines.push('Gewerke (aus LV-Positionen): ' + Array.from(catPaths).join(', '));
    }
  }

  // Archive folder names — often the most descriptive label for multi-lot tenders
  const otherNames = (archiveSummary && archiveSummary.other_names) || [];
  const folders = new Set();
  for (const p of otherNames) {
    const ext = ('.' + p.split('.').pop()).toLowerCase();
    if (gaebLikeExts.includes(ext)) {
      const parts = p.replace(/\\/g, '/').split('/');
      if (parts.length >= 3) {
        const folder = parts[parts.length - 2];
        if (folder && !/^heftung\d*$/i.test(folder) && folder.length > 4) folders.add(folder);
      }
    }
  }
  if (folders.size > 0) lines.push('Teilleistungen/Lose (aus Archivstruktur): ' + Array.from(folders).join(', '));

  // PDF names that look like LV documents
  const pdfNames = (archiveSummary && archiveSummary.pdf_names) || [];
  const lvPdfs = pdfNames.filter(n => /lv|leistung|ausschreib/i.test(n)).slice(0, 3);
  if (lvPdfs.length > 0) lines.push('LV-Dokumente: ' + lvPdfs.join(', '));

  // Key PDF text (211 = Aufforderung zur Angebotsabgabe, 214 = BVB)
  // These PDFs contain the full untruncated project title and buyer name
  // that GAEB XML XSD field limits (NamePrj=60 chars, Name1=40 chars) cut short.
  if (pdfTexts) {
    const pdfOrder = ['211', '214', '213', '216'];
    for (const cat of pdfOrder) {
      const text = pdfTexts[cat];
      if (text && typeof text === 'string' && text.trim().length > 20) {
        lines.push('--- Auszug aus PDF-Dokument (' + cat + ') ---');
        lines.push(text.slice(0, 1500));
        break; // One PDF is enough for title/buyer context
      }
    }
  }

  return lines.join('\n') || 'Keine GAEB-Daten verfügbar.';
}

const primary = gaebFiles.find(g => parseInt(g?.metadata?.data_phase, 10) === 82) || gaebFiles[0] || {};
const totalItems = gaebFiles.reduce((s, g) => s + (g.bill_of_quantities?.total_items || 0), 0);

const gaebPositions = gaebFiles.flatMap(g => {
  if (g._error) return [];
  const entries = g.bill_of_quantities?.entries || [];
  return entries.filter(e => e.type === 'item').slice(0, 200).map(e => ({
    id: e.position || e.id || '',
    short_text: e.short_text || '',
    long_text: (e.long_text || '').slice(0, 200),
    quantity: e.quantity || null,
    unit: e.unit || null,
    category_path: e.category_path || [],
    gaeb_phase: parseInt(g.metadata?.data_phase, 10) || null,
  }));
});

return [{ json: {
  id: input.tender_id,
  org_id: input.org_id,
  user_id: input.user_id,
  // Structural fields deterministically derived from GAEB XML
  gaeb_phase: parseInt(primary.metadata?.data_phase, 10) || null,
  item_count: totalItems,
  lot_count: gaebFiles.length,
  source_type: 'gaeb',
  source_filename: input.source_filename || '',
  has_plans: input.has_plans || false,
  raw_gaeb_json: gaebFiles,
  gaeb_positions: gaebPositions,
  pdf_text: serializeGaebText(gaebFiles),
  processing_status: 'metadata_ready',
  // AI metadata extraction context (consumed by extract-metadata-llm node)
  _gaeb_context: buildContextForAI(gaebFiles, input.archive_summary, input.pdf_texts),
} }];

