  "trade_category": "Primäres Gewerk auf Deutsch (z.B. Kanalbau, Straßenbau, Hochbau, Elektrotechnik, Tiefbau) oder null"
}' }, { role: 'user', content: $json._gaeb_context }], temperature: 0 }) }}

