const aiResponse = $json;
const normalised = $('normalise').first().json;

let meta = {};
try {
  const content = aiResponse.choices[0].message.content;
  const cleaned = content.replace(/```json/g, '').replace(/```/g, '').trim();
  meta = JSON.parse(cleaned);
} catch (e) {
  // AI response unparseable — fall through with empty meta, structural fields remain
}

return [{ json: {
  id: normalised.id,
  org_id: normalised.org_id,
  user_id: normalised.user_id,
  // AI-derived metadata (with structural fallbacks)
  title: (meta.title && meta.title.trim()) || 'Leistungsverzeichnis',
  buyer: meta.buyer || null,
  region: meta.region || null,
  deadline: meta.deadline || null,
  trade_category: meta.trade_category || null,
  // Structurally derived fields (deterministic, not sent to AI)
  gaeb_phase: normalised.gaeb_phase,
  item_count: normalised.item_count,
  lot_count: normalised.lot_count,
  source_type: normalised.source_type,
  source_filename: normalised.source_filename,
  has_plans: normalised.has_plans,
  raw_gaeb_json: normalised.raw_gaeb_json,
  gaeb_positions: normalised.gaeb_positions,
  pdf_text: normalised.pdf_text,
  processing_status: 'metadata_ready',
} }];
